SELECT codigo, nombre, sector, producto, litros, tn, nivel_pct, fuente_medicion
FROM reporting.v_tanques
ORDER BY litros DESC;

SELECT codigo, litros_medido, delta_litros_ejecutado, litros_estimado, fuente_medicion, antiguedad_min, confianza
FROM reporting.v_tanque_stock_estimado
ORDER BY litros_estimado DESC;

SELECT ticket_mov, estado_mov, rol, COALESCE(producto,codigo_insumo) item, fuente, COALESCE(tanque_label,ticket_porteria) origen, cantidad, unidad
FROM reporting.v_movimientos_stock
ORDER BY momento DESC LIMIT 20;

SELECT severidad, COUNT(*) lecturas, round(AVG(abs(discrepancia_litros)),0) disc_prom_litros
FROM reporting.v_reconciliacion_stock
GROUP BY severidad ORDER BY severidad;
